const requestSchema = z.object({
  figmaLink: z.string().trim().optional(),
  prompt: z.string().trim().min(3, "Describe what you want to build."),
  referenceImage: z
    .object({
      data: z.string().min(1),
      mimeType: z.string().min(1),
      name: z.string().min(1),
    })
    .optional(),
  currentGeneration: z
    .object({
      id: z.string().optional(),
      title: z.string().optional(),
      summary: z.string().optional(),
      prompt: z.string().optional(),
      previewHtml: z.string().optional(),
      previewCss: z.string().optional(),
      previewJs: z.string().optional(),
      files: z
        .array(
          z.object({
            path: z.string().min(1),
            content: z.string(),
          }),
        )
        .optional(),
    })
    .optional(),
});

const generationSchema = z.object({
  title: z.string().min(1),
  summary: z.string().min(1),
  previewHtml: z.string().min(1),
  previewCss: z.string().min(1),
  previewJs: z.string().optional().default(""),
  files: z
    .array(
      z.object({
        path: z.string().min(1),
        content: z.string(),
      }),
    )
    .min(1),
  notes: z.array(z.string()).optional().default([]),
});

const fileChangeSchema = z.object({
  path: z.string().min(1),
  action: z.enum(["created", "edited"]),
});

const WEBSITE_GENERATION_SYSTEM_PROMPT = `SYSTEM PROMPT:
You are an expert senior frontend engineer and product designer. You build beautiful, polished, production-ready React + Tailwind websites. Your output should look like something generated by v0, Lovable, Framer, or a high-end design agency.

For every user request:
- First understand the exact type of website/app requested.
- Choose a strong visual direction.
- Create a design system with colors, typography, spacing, cards, buttons, and layout rules.
- Generate a complete responsive website.
- Use realistic content.
- Use modern Tailwind styling.
- Use icons where useful using CSS, text symbols, or inline-safe shapes; do not import icon packages unless already included.
- Use gradients, glassmorphism, soft shadows, hover states, transitions, and micro-interactions where appropriate.
- Make the UI feel complete and premium.
- Make every section useful and visually intentional.

QUALITY BAR:
The output must not look like a beginner project. It should look like a polished portfolio/demo-worthy product.

Internal design checklist before returning:
- Is the page visually premium?
- Is spacing consistent?
- Is typography modern?
- Are sections complete?
- Are cards populated with real content?
- Are buttons styled properly?
- Is the layout responsive?
- Does the result match the user prompt?
- Does it look better than a basic HTML mockup?

Never generate plain white pages with random boxes, empty cards, unstyled navbars, misaligned sections, placeholder-only text, huge blank spaces, unfinished sections, or single-color rectangles pretending to be components.`;

const PREMIUM_OUTPUT_REQUIREMENTS = `PREMIUM OUTPUT REQUIREMENTS:
- Generate a finished product experience, not a sketch, wireframe, starter screen, or tutorial mockup.
- The first viewport must look impressive immediately and fill the available preview area.
- Use a real visual system: deliberate background, surfaces, borders, shadows, accent color, type scale, spacing rhythm, and hover states.
- Use domain-specific content. Never use generic labels like "Video Title", "Product Name", "Card title", "Feature one", or lorem ipsum.
- Include enough repeated realistic items to feel real: feeds need many posts, video apps need many video cards, stores need many products, dashboards need many metrics/rows, landing pages need complete sections.
- Avoid tiny demos with one card, one section, one centered panel, or lots of empty whitespace.
- Preview markup must be rich enough to judge the result without running React.
- React output and preview output must visually match.
- Prefer tasteful density over sparse emptiness. Use layered sections, split layouts, sidebars, tabs, chips, tables, cards, mockups, and data where appropriate.
- Use responsive layouts that meaningfully change on mobile instead of just shrinking desktop.
- Keep code clean, but prioritize visual completeness and prompt accuracy.`;

