export async function POST(request: Request) {
  const session = await getServerSession(authOptions);

  if (!session?.user) {
    return NextResponse.json({ error: "You must be signed in to generate." }, { status: 401 });
  }

  const provider = getAiProvider();
  const apiKey = provider === "openrouter" ? process.env.OPENROUTER_API_KEY : process.env.GEMINI_API_KEY;

  const body = await request.json().catch(() => null);
  const parsed = requestSchema.safeParse(body);

  if (!parsed.success) {
    return NextResponse.json({ error: parsed.error.issues[0]?.message ?? "Invalid request." }, { status: 400 });
  }

  const client = await clientPromise;
  const db = client.db();
  const users = db.collection<UserAccount>("users");
  const creditReservation = await reserveGenerationCredit(users, session.user);

  if (!creditReservation) {
    return NextResponse.json({ error: "Account not found." }, { status: 404 });
  }

  if (!creditReservation.ok) {
    return NextResponse.json(
      { error: "You are out of credits. Buy a plan to keep generating.", creditsRemaining: creditReservation.credits, creditLimit: FREE_SIGNUP_CREDITS },
      { status: 402 },
    );
  }

  try {
    let result: z.infer<typeof generationSchema>;

    if (!apiKey) {
      console.warn(`[Mosaic generation] ${provider} API key is not configured; using local reliable generation.`);
      result = createReliableGeneration(parsed.data.prompt, "AI provider key missing");
    } else {
      try {
        result = enforceGenerationQuality(
          parsed.data.prompt,
          await generateWithAi({
            provider,
            apiKey,
            figmaLink: parsed.data.figmaLink,
            prompt: parsed.data.prompt,
            referenceImage: parsed.data.referenceImage,
            currentGeneration: parsed.data.currentGeneration,
          }),
        );

        const qualityIssues = validateGeneratedQuality(parsed.data.prompt, result);

        if (qualityIssues.length) {
          console.warn(`[Mosaic generation] generated UI quality warnings: ${qualityIssues.join("; ")}; using local reliable generation.`);
          result = createReliableGeneration(parsed.data.prompt, qualityIssues.join("; "));
        }
      } catch (error) {
        console.warn(`[Mosaic generation] AI provider failed; using local reliable generation: ${error instanceof Error ? error.message : "Unknown error."}`);
        result = createReliableGeneration(parsed.data.prompt, error instanceof Error ? error.message : "AI provider failed");
      }
    }

    const now = new Date();
    const generationRecord = {
      ...result,
      prompt: parsed.data.prompt,
      figmaLink: parsed.data.figmaLink,
      referenceImageName: parsed.data.referenceImage?.name,
      userId: creditReservation.userId,
      generatedAt: now,
      updatedAt: now,
    };
    const currentGenerationId = parsed.data.currentGeneration?.id;
    let generationId = "";

    if (currentGenerationId && ObjectId.isValid(currentGenerationId)) {
      const updated = await db.collection("generations").findOneAndUpdate(
        { _id: new ObjectId(currentGenerationId), userId: creditReservation.userId },
        { $set: generationRecord },
        { returnDocument: "after", projection: { _id: 1 } },
      );

      generationId = updated.value?._id.toString() ?? "";
    }

    if (!generationId) {
      const saved = await db.collection("generations").insertOne({
        ...generationRecord,
        createdAt: now,
      });
      generationId = saved.insertedId.toString();
    }

    return NextResponse.json({
      generation: result,
      generationId,
      filesChanged: getFileChanges(result.files, parsed.data.currentGeneration?.files ?? []),
      creditsRemaining: creditReservation.credits,
      creditLimit: FREE_SIGNUP_CREDITS,
    });
  } catch (error) {
    await refundGenerationCredit(users, creditReservation.userId);
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Generation failed. Please try again." },
      { status: 500 },
    );
  }
}

function getFileChanges(nextFiles: z.infer<typeof generationSchema>["files"], previousFiles: Array<{ path: string; content: string }>) {
  const previousByPath = new Map(previousFiles.map((file) => [file.path, file.content]));

  return nextFiles
    .map((file) => {
      const previousContent = previousByPath.get(file.path);

      if (previousContent === undefined) {
        return { path: file.path, action: "created" as const };
      }

      if (previousContent !== file.content) {
        return { path: file.path, action: "edited" as const };
      }

      return null;
    })
    .filter((fileChange): fileChange is z.infer<typeof fileChangeSchema> => Boolean(fileChange));
}

function enforceGenerationQuality(prompt: string, generation: z.infer<typeof generationSchema>) {
  const qualityIssues = validateGeneratedQuality(prompt, generation);

  if (qualityIssues.length) {
    console.warn(`[Mosaic generation] generated UI quality warnings: ${qualityIssues.join("; ")}`);
  }

  return generation;
}

function validateGeneratedQuality(prompt: string, generation: z.infer<typeof generationSchema>) {
  const content = `${generation.previewHtml} ${generation.previewCss} ${generation.files.map((file) => file.content).join(" ")}`.toLowerCase();
  const issues: string[] = [];
  const sectionCount = (content.match(/<section|section class|function [a-z0-9]+section|const [a-z0-9]+section/gi) ?? []).length;
  const cardSignals = (content.match(/card|article|grid|thumbnail|product|metric|testimonial/g) ?? []).length;
  const repeatedItemSignals = (content.match(/article|post|tweet|video|product|row|metric|testimonial|card|item/g) ?? []).length;
  const hasResponsiveClasses = /\b(sm|md|lg|xl|2xl):/.test(content) || /@media\s*\(/.test(content);
  const hasStyledButton = /button|rounded-full|hover:|transition/.test(content);
  const hasNavigation = /<nav|navitems|navbar|sidebar|topbar|header/.test(content);
  const hasPlaceholderOnlyText = /video title|lorem ipsum|placeholder|card title|product name/i.test(content);
  const isComplexPrompt = /clone|dashboard|analytics|social|video|youtube|twitter|facebook|ecommerce|store|shop|marketplace|app/i.test(prompt);

  if (sectionCount < 4 && !/clone|dashboard|app interface/i.test(prompt)) issues.push("too few meaningful sections");
  if (isComplexPrompt && cardSignals < 10) issues.push("too few repeated cards/items");
  if (isComplexPrompt && repeatedItemSignals < 12) issues.push("too little realistic repeated content");
  if (!hasResponsiveClasses) issues.push("missing responsive Tailwind/media classes");
  if (!hasStyledButton) issues.push("buttons or interactions are under-styled");
  if (!hasNavigation) issues.push("navigation is missing or weak");
  if (hasPlaceholderOnlyText) issues.push("placeholder-only copy detected");
  if (generation.previewHtml.length < 4500 || generation.previewCss.length < 2200) issues.push("preview is too small/basic");

  return issues;
}

function createReliableGeneration(prompt: string, reason: string): z.infer<typeof generationSchema> {
  const analysis = analyzePrompt(prompt);
  const title = getFallbackTitle(prompt, analysis.websiteType);
  const theme = getFallbackTheme(analysis.websiteType);
  const sections = getReliableSections(prompt, analysis.websiteType);
  const previewHtml = renderReliablePreview({ title, prompt, sections, theme, websiteType: analysis.websiteType });
  const previewCss = renderReliableCss(theme);
  const appFile = renderReliableApp({ title, prompt, sections, theme, websiteType: analysis.websiteType });

  return {
    title,
    summary: `A polished ${analysis.websiteType.replace(/-/g, " ")} generated for: ${prompt}.`,
    previewHtml,
    previewCss,
    previewJs: "",
    files: createReliableFiles(appFile, title),
    notes: [`Used reliable local generation because ${reason}.`],
  };
}

type ReliableSection = {
  eyebrow: string;
  title: string;
  description: string;
  items: Array<{ title: string; meta: string; description: string }>;
};

type ReliableTheme = {
  background: string;
  surface: string;
  surfaceAlt: string;
  text: string;
  muted: string;
  accent: string;
  accentSoft: string;
  border: string;
};

function getFallbackTitle(prompt: string, websiteType: WebsiteType) {
  const clean = prompt
    .replace(/\b(build|make|create|design|generate|please|a|an|the|website|site|app|page|clone|for|me)\b/gi, " ")
    .replace(/\s+/g, " ")
    .trim();

  if (/youtube|video/i.test(prompt)) return "YouTube";
  if (/twitter|x clone|tweet/i.test(prompt)) return "Pulse";
  if (/facebook/i.test(prompt)) return "Connect";
  if (/ecommerce|shop|store|product/i.test(prompt)) return "Nova Store";
  if (/dashboard|analytics|admin/i.test(prompt)) return "Mosaic Analytics";
  if (/cafe|coffee|restaurant/i.test(prompt)) return "Lumen Cafe";
  if (/portfolio/i.test(prompt)) return "Studio Portfolio";

  return clean ? toTitleCase(clean).slice(0, 42) : toTitleCase(websiteType.replace(/-/g, " "));
}

function getFallbackTheme(websiteType: WebsiteType): ReliableTheme {
  if (websiteType === "fashion-ecommerce" || websiteType === "restaurant-cafe") {
    return {
      background: "#f8f3ec",
      surface: "rgba(255,255,255,.72)",
      surfaceAlt: "#1f1712",
      text: "#211a16",
      muted: "#77685d",
      accent: "#a15c38",
      accentSoft: "rgba(161,92,56,.14)",
      border: "rgba(33,26,22,.12)",
    };
  }

  return {
    background: "#09090b",
    surface: "rgba(255,255,255,.075)",
    surfaceAlt: "rgba(255,255,255,.11)",
    text: "#f8fafc",
    muted: "#a1a1aa",
    accent: "#38bdf8",
    accentSoft: "rgba(56,189,248,.14)",
    border: "rgba(255,255,255,.12)",
  };
}

